 1	import React, { FC } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { Checkbox, Flex, FlexItem, FormGroup, Popover } from '@patternfly/react-core';
 5	import { HelpIcon } from '@patternfly/react-icons';
 6	
 7	type BootCDCheckboxProps = {
 8	  hasCDSource: boolean;
 9	  onChange: (checked: boolean) => void;
10	};
11	
12	const BootCDCheckbox: FC<BootCDCheckboxProps> = ({ hasCDSource, onChange }) => {
13	  const { t } = useKubevirtTranslation();
14	
15	  return (
16	    <FormGroup className="disk-source-form-group" fieldId="customize-boot-from-cd">
17	      <Flex>
18	        <FlexItem>
19	          <Checkbox
20	            data-test-id="boot-cd"
21	            id="boot-cd"
22	            isChecked={hasCDSource}
23	            label={t('Boot from CD')}
24	            onChange={(_, checked: boolean) => onChange(checked)}
25	          />
26	        </FlexItem>
27	        <FlexItem>
28	          <Popover
29	            bodyContent={() => (
30	              <div>
31	                {t(
32	                  'Boot from CD requires an image file i.e. ISO, qcow, etc. that will be mounted to the VirtualMachine as a CD',
33	                )}
34	              </div>
35	            )}
36	            aria-label={'Help'}
37	          >
38	            <HelpIcon />
39	          </Popover>
40	        </FlexItem>
41	      </Flex>
42	    </FormGroup>
43	  );
44	};
45	
46	export default BootCDCheckbox;

